# NOTE: This file is read at runtime by server/src/services/haproxy/haproxy-service.ts
# and written into the haproxy_config Docker volume. Changes here take effect on next Start.
#
# Domain to Backend Mapping
# Format: <domain> <backend_name>
#
# This file is used by HAProxy to route traffic based on SNI (Server Name Indication).
# When a client connects via HTTPS, HAProxy reads the requested domain from the TLS handshake
# and routes the request to the appropriate backend.
#
# Example entries:
# example.com           backend_example
# www.example.com       backend_example
# api.example.com       backend_api
# *.example.com         backend_example_wildcard
#
# Add your domain mappings below:

